    // .NET 9 breaking change: on Linux, empty env vars now return null
    // instead of "". Use an explicit empty-string check to preserve the
    // distinction between "not set" and "explicitly empty".
    var val = Environment.GetEnvironmentVariable("MY_FLAG");
