// Reads /proc/self/environ to distinguish "not set" from "set to empty".
static bool IsEnvironmentVariableDefined(string name)
{
    if (!OperatingSystem.IsLinux()) return false;
    try
    {
        var environ = System.IO.File.ReadAllText("/proc/self/environ");
        // Entries are separated by '\0'; each is "KEY=VALUE".
        return environ.Split('\0').Any(e =>
            e == name + "=" || e.StartsWith(name + "=", StringComparison.Ordinal));
    }
    catch { return false; }
}

